// AUTO-GENERISANO iz sistemi_signali.i18n.map.js — poravnato sa _sistemi_signali_strings.json
// Oblik: [{en,de,fr,es,it,ru,pt}, ...] paralelno sa strings.json (ugovor gen_*.js).
module.exports = [{"en":"Remember","de":"Merke","fr":"Retenir","es":"Recuerda","it":"Ricorda","ru":"Запомни","pt":"Lembre-se"},{"en":"Example","de":"Beispiel","fr":"Exemple","es":"Ejemplo","it":"Esempio","ru":"Пример","pt":"Exemplo"},{"en":"Singular signals","de":"Singuläre Signale","fr":"Signaux singuliers","es":"Señales singulares","it":"Segnali singolari","ru":"Сингулярные сигналы","pt":"Sinais singulares"},{"en":"Singular signals are idealizations that describe abrupt changes. The most important are the Dirac impulse","de":"Singuläre Signale sind Idealisierungen, die abrupte Änderungen beschreiben. Die wichtigsten sind der Dirac-Impuls","fr":"Les signaux singuliers sont des idéalisations décrivant des changements brusques. Les plus importants sont l'impulsion de Dirac","es":"Las señales singulares son idealizaciones que describen cambios bruscos. Las más importantes son el impulso de Dirac","it":"I segnali singolari sono idealizzazioni che descrivono cambiamenti bruschi. I più importanti sono l'impulso di Dirac","ru":"Сингулярные сигналы — идеализации, описывающие резкие изменения. Важнейшие из них: дельта-функция Дирака","pt":"Os sinais singulares são idealizações que descrevem mudanças abruptas. Os mais importantes são o impulso de Dirac"},{"en":"Heaviside step","de":"Heaviside-Sprung","fr":"échelon de Heaviside","es":"escalón de Heaviside","it":"gradino di Heaviside","ru":"единичный скачок Хевисайда","pt":"degrau de Heaviside"},{"en":"and the ramp signal","de":"und das Rampensignal","fr":"et le signal rampe","es":"y la señal rampa","it":"e il segnale rampa","ru":"и линейно нарастающий сигнал","pt":"e o sinal rampa"},{"en":"They are related by differentiation and integration.","de":"Sie sind durch Ableitung und Integration verbunden.","fr":"Ils sont liés par dérivation et intégration.","es":"Están relacionados por derivación e integración.","it":"Sono legati da derivazione e integrazione.","ru":"Они связаны дифференцированием и интегрированием.","pt":"Estão relacionados por derivação e integração."},{"en":"Dirac impulse (defining property)","de":"Dirac-Impuls (definierende Eigenschaft)","fr":"impulsion de Dirac (propriété de définition)","es":"impulso de Dirac (propiedad definitoria)","it":"impulso di Dirac (proprietà definitoria)","ru":"дельта-функция Дирака (определяющее свойство)","pt":"impulso de Dirac (propriedade definidora)"},{"en":"Sifting property","de":"Ausblendeigenschaft","fr":"propriété de sélection","es":"propiedad de muestreo","it":"proprietà di campionamento","ru":"фильтрующее свойство","pt":"propriedade de filtragem"},{"en":"Relation of step and impulse","de":"Beziehung von Sprung und Impuls","fr":"relation échelon-impulsion","es":"relación escalón-impulso","it":"relazione gradino-impulso","ru":"связь скачка и импульса","pt":"relação degrau-impulso"},{"en":"Ramp signal","de":"Rampensignal","fr":"signal rampe","es":"señal rampa","it":"segnale rampa","ru":"линейный сигнал","pt":"sinal rampa"},{"en":"Compute","de":"Berechne","fr":"Calculer","es":"Calcular","it":"Calcolare","ru":"Вычислить","pt":"Calcular"},{"en":"By the sifting property the integral extracts the value of the function at","de":"Nach der Ausblendeigenschaft liefert das Integral den Funktionswert bei","fr":"Par la propriété de sélection, l'intégrale extrait la valeur de la fonction en","es":"Por la propiedad de muestreo, la integral extrae el valor de la función en","it":"Per la proprietà di campionamento l'integrale estrae il valore della funzione in","ru":"По фильтрующему свойству интеграл выделяет значение функции в","pt":"Pela propriedade de filtragem a integral extrai o valor da função em"},{"en":"Regular signals and operations on them","de":"Reguläre Signale und Operationen","fr":"Signaux réguliers et opérations","es":"Señales regulares y operaciones","it":"Segnali regolari e operazioni","ru":"Регулярные сигналы и операции над ними","pt":"Sinais regulares e operações"},{"en":"Regular signals are described by operations: time shift, scaling and reflection. Important classes are even and odd signals, and periodic signals. Signal size is measured by energy and power.","de":"Reguläre Signale werden durch Operationen beschrieben: Zeitverschiebung, Skalierung und Spiegelung. Wichtige Klassen sind gerade und ungerade sowie periodische Signale. Die Größe misst man durch Energie und Leistung.","fr":"Les signaux réguliers sont décrits par des opérations : décalage temporel, mise à l'échelle et réflexion. Les classes importantes sont les signaux pairs et impairs et périodiques. La taille se mesure par l'énergie et la puissance.","es":"Las señales regulares se describen mediante operaciones: desplazamiento temporal, escalado y reflexión. Clases importantes son las señales pares e impares y periódicas. El tamaño se mide por energía y potencia.","it":"I segnali regolari si descrivono con operazioni: traslazione temporale, scalatura e riflessione. Classi importanti sono i segnali pari e dispari e periodici. La grandezza si misura con energia e potenza.","ru":"Регулярные сигналы описываются операциями: сдвиг во времени, масштабирование и отражение. Важные классы — чётные и нечётные, а также периодические сигналы. Величину измеряют энергией и мощностью.","pt":"Os sinais regulares descrevem-se por operações: deslocamento temporal, escalonamento e reflexão. Classes importantes são os sinais pares e ímpares e periódicos. O tamanho mede-se por energia e potência."},{"en":"Shift and scaling","de":"Verschiebung und Skalierung","fr":"Décalage et mise à l'échelle","es":"Desplazamiento y escalado","it":"Traslazione e scalatura","ru":"Сдвиг и масштабирование","pt":"Deslocamento e escalonamento"},{"en":"Even and odd part","de":"Gerader und ungerader Teil","fr":"Partie paire et impaire","es":"Parte par e impar","it":"Parte pari e dispari","ru":"Чётная и нечётная части","pt":"Parte par e ímpar"},{"en":"Signal energy","de":"Signalenergie","fr":"Énergie du signal","es":"Energía de la señal","it":"Energia del segnale","ru":"Энергия сигнала","pt":"Energia do sinal"},{"en":"Power of a periodic signal","de":"Leistung eines periodischen Signals","fr":"Puissance d'un signal périodique","es":"Potencia de una señal periódica","it":"Potenza di un segnale periodico","ru":"Мощность периодического сигнала","pt":"Potência de um sinal periódico"},{"en":"Find the energy of the signal","de":"Bestimme die Energie des Signals","fr":"Trouver l'énergie du signal","es":"Hallar la energía de la señal","it":"Trovare l'energia del segnale","ru":"Найти энергию сигнала","pt":"Encontrar a energia do sinal"},{"en":"The energy is finite, so the signal is an energy signal.","de":"Die Energie ist endlich, also ist es ein Energiesignal.","fr":"L'énergie est finie, donc le signal est un signal d'énergie.","es":"La energía es finita, por lo que es una señal de energía.","it":"L'energia è finita, quindi è un segnale di energia.","ru":"Энергия конечна, поэтому сигнал — энергетический.","pt":"A energia é finita, logo é um sinal de energia."},{"en":"Continuous-time convolution","de":"Faltung in kontinuierlicher Zeit","fr":"Convolution en temps continu","es":"Convolución en tiempo continuo","it":"Convoluzione a tempo continuo","ru":"Свёртка в непрерывном времени","pt":"Convolução em tempo contínuo"},{"en":"Convolution describes the response of a linear time-invariant system to an arbitrary input. The output is the convolution of the input and the impulse response.","de":"Die Faltung beschreibt die Antwort eines linearen zeitinvarianten Systems auf einen beliebigen Eingang. Der Ausgang ist die Faltung von Eingang und Impulsantwort.","fr":"La convolution décrit la réponse d'un système linéaire invariant dans le temps à une entrée arbitraire. La sortie est la convolution de l'entrée et de la réponse impulsionnelle.","es":"La convolución describe la respuesta de un sistema lineal e invariante en el tiempo a una entrada arbitraria. La salida es la convolución de la entrada y la respuesta al impulso.","it":"La convoluzione descrive la risposta di un sistema lineare tempo-invariante a un ingresso arbitrario. L'uscita è la convoluzione dell'ingresso e della risposta all'impulso.","ru":"Свёртка описывает отклик линейной стационарной системы на произвольный вход. Выход — свёртка входа и импульсной характеристики.","pt":"A convolução descreve a resposta de um sistema linear e invariante no tempo a uma entrada arbitrária. A saída é a convolução da entrada e da resposta ao impulso."},{"en":"Definition of convolution","de":"Definition der Faltung","fr":"Définition de la convolution","es":"Definición de convolución","it":"Definizione di convoluzione","ru":"Определение свёртки","pt":"Definição de convolução"},{"en":"Commutativity","de":"Kommutativität","fr":"Commutativité","es":"Conmutatividad","it":"Commutatività","ru":"Коммутативность","pt":"Comutatividade"},{"en":"Convolution identity","de":"Neutrales Element der Faltung","fr":"Élément neutre de la convolution","es":"Neutro de la convolución","it":"Elemento neutro della convoluzione","ru":"Нейтральный элемент свёртки","pt":"Elemento neutro da convolução"},{"en":"Shifted impulse","de":"Verschobener Impuls","fr":"Impulsion décalée","es":"Impulso desplazado","it":"Impulso traslato","ru":"Сдвинутый импульс","pt":"Impulso deslocado"},{"en":"Find","de":"Bestimme","fr":"Trouver","es":"Hallar","it":"Trovare","ru":"Найти","pt":"Encontrar"},{"en":"The integrand is","de":"Der Integrand ist","fr":"L'intégrande est","es":"El integrando es","it":"L'integranda è","ru":"Подынтегральная функция равна","pt":"O integrando é"},{"en":"for","de":"für","fr":"pour","es":"para","it":"per","ru":"при","pt":"para"},{"en":"otherwise zero.","de":"sonst null.","fr":"sinon zéro.","es":"de lo contrario cero.","it":"altrimenti zero.","ru":"иначе ноль.","pt":"caso contrário zero."},{"en":"Bilateral Laplace transform and region of convergence","de":"Bilaterale Laplace-Transformation und Konvergenzbereich","fr":"Transformée de Laplace bilatérale et région de convergence","es":"Transformada de Laplace bilateral y región de convergencia","it":"Trasformata di Laplace bilatera e regione di convergenza","ru":"Двустороннее преобразование Лапласа и область сходимости","pt":"Transformada de Laplace bilateral e região de convergência"},{"en":"The bilateral Laplace transform maps a time signal to a function of the complex variable","de":"Die bilaterale Laplace-Transformation bildet ein Zeitsignal auf eine Funktion der komplexen Variablen ab","fr":"La transformée de Laplace bilatérale envoie un signal temporel sur une fonction de la variable complexe","es":"La transformada de Laplace bilateral asigna una señal temporal a una función de la variable compleja","it":"La trasformata di Laplace bilatera trasforma un segnale temporale in una funzione della variabile complessa","ru":"Двустороннее преобразование Лапласа отображает временной сигнал в функцию комплексной переменной","pt":"A transformada de Laplace bilateral leva um sinal temporal a uma função da variável complexa"},{"en":"The region of convergence (ROC) is always stated with the transform, since it uniquely determines the signal.","de":"Mit der Transformation gibt man stets den Konvergenzbereich (ROC) an, da er das Signal eindeutig bestimmt.","fr":"On indique toujours la région de convergence (ROC) avec la transformée, car elle détermine le signal de façon unique.","es":"Siempre se indica la región de convergencia (ROC) junto con la transformada, pues determina la señal de forma única.","it":"Con la trasformata si indica sempre la regione di convergenza (ROC), poiché determina univocamente il segnale.","ru":"Вместе с преобразованием всегда указывают область сходимости (ОС), так как она однозначно определяет сигнал.","pt":"Junto da transformada indica-se sempre a região de convergência (ROC), pois determina o sinal de forma única."},{"en":"Bilateral definition","de":"Bilaterale Definition","fr":"Définition bilatérale","es":"Definición bilateral","it":"Definizione bilatera","ru":"Двустороннее определение","pt":"Definição bilateral"},{"en":"Right-sided signal","de":"Rechtsseitiges Signal","fr":"Signal causal (à droite)","es":"Señal de lado derecho","it":"Segnale destro","ru":"Правосторонний сигнал","pt":"Sinal lateral direito"},{"en":"Left-sided signal","de":"Linksseitiges Signal","fr":"Signal anticausal (à gauche)","es":"Señal de lado izquierdo","it":"Segnale sinistro","ru":"Левосторонний сигнал","pt":"Sinal lateral esquerdo"},{"en":"The region of convergence is a strip","de":"Der Konvergenzbereich ist ein Streifen","fr":"La région de convergence est une bande","es":"La región de convergencia es una banda","it":"La regione di convergenza è una striscia","ru":"Область сходимости — полоса","pt":"A região de convergência é uma faixa"},{"en":"Find the transform and ROC for","de":"Bestimme Transformierte und ROC für","fr":"Trouver la transformée et la ROC pour","es":"Hallar la transformada y la ROC de","it":"Trovare la trasformata e la ROC per","ru":"Найти преобразование и ОС для","pt":"Encontrar a transformada e a ROC de"},{"en":"The integral converges for","de":"Das Integral konvergiert für","fr":"L'intégrale converge pour","es":"La integral converge para","it":"L'integrale converge per","ru":"Интеграл сходится при","pt":"A integral converge para"},{"en":"Unilateral Laplace transform and properties","de":"Einseitige Laplace-Transformation und Eigenschaften","fr":"Transformée de Laplace unilatérale et propriétés","es":"Transformada de Laplace unilateral y propiedades","it":"Trasformata di Laplace unilatera e proprietà","ru":"Одностороннее преобразование Лапласа и свойства","pt":"Transformada de Laplace unilateral e propriedades"},{"en":"The unilateral (one-sided) Laplace transform suits causal signals and solving equations with initial conditions, since the differentiation property explicitly involves the initial values.","de":"Die einseitige Laplace-Transformation eignet sich für kausale Signale und das Lösen von Gleichungen mit Anfangsbedingungen, da in der Ableitungseigenschaft die Anfangswerte explizit vorkommen.","fr":"La transformée de Laplace unilatérale convient aux signaux causaux et à la résolution d'équations avec conditions initiales, car la propriété de dérivation fait intervenir explicitement les valeurs initiales.","es":"La transformada de Laplace unilateral es adecuada para señales causales y para resolver ecuaciones con condiciones iniciales, pues la propiedad de derivación incluye explícitamente los valores iniciales.","it":"La trasformata di Laplace unilatera è adatta ai segnali causali e alla soluzione di equazioni con condizioni iniziali, poiché la proprietà di derivazione coinvolge esplicitamente i valori iniziali.","ru":"Одностороннее преобразование Лапласа удобно для причинных сигналов и решения уравнений с начальными условиями, так как в свойстве производной явно участвуют начальные значения.","pt":"A transformada de Laplace unilateral é adequada a sinais causais e à resolução de equações com condições iniciais, pois a propriedade da derivada envolve explicitamente os valores iniciais."},{"en":"Definition","de":"Definition","fr":"Définition","es":"Definición","it":"Definizione","ru":"Определение","pt":"Definição"},{"en":"Linearity","de":"Linearität","fr":"Linéarité","es":"Linealidad","it":"Linearità","ru":"Линейность","pt":"Linearidade"},{"en":"Derivative","de":"Ableitung","fr":"Dérivée","es":"Derivada","it":"Derivata","ru":"Производная","pt":"Derivada"},{"en":"Time shift","de":"Zeitverschiebung","fr":"Décalage temporel","es":"Desplazamiento temporal","it":"Traslazione temporale","ru":"Сдвиг во времени","pt":"Deslocamento temporal"},{"en":"From Euler's formula and the table","de":"Aus der Eulerschen Formel und der Tabelle","fr":"D'après la formule d'Euler et la table","es":"A partir de la fórmula de Euler y la tabla","it":"Dalla formula di Eulero e dalla tabella","ru":"По формуле Эйлера и таблице","pt":"A partir da fórmula de Euler e da tabela"},{"en":"Inverse Laplace transform","de":"Inverse Laplace-Transformation","fr":"Transformée de Laplace inverse","es":"Transformada inversa de Laplace","it":"Trasformata inversa di Laplace","ru":"Обратное преобразование Лапласа","pt":"Transformada inversa de Laplace"},{"en":"The inverse transform of a rational function is found by partial-fraction expansion, recognizing each term from the table. The poles determine the form of the time response.","de":"Die Rücktransformierte einer rationalen Funktion findet man durch Partialbruchzerlegung und erkennt jeden Term aus der Tabelle. Die Pole bestimmen die Form der Zeitantwort.","fr":"La transformée inverse d'une fonction rationnelle s'obtient par décomposition en éléments simples, chaque terme étant reconnu dans la table. Les pôles déterminent la forme de la réponse temporelle.","es":"La transformada inversa de una función racional se halla por descomposición en fracciones simples, reconociendo cada término en la tabla. Los polos determinan la forma de la respuesta temporal.","it":"La trasformata inversa di una funzione razionale si trova con la scomposizione in fratti semplici, riconoscendo ogni termine dalla tabella. I poli determinano la forma della risposta temporale.","ru":"Обратное преобразование рациональной функции находят разложением на простейшие дроби, узнавая каждый член по таблице. Полюсы определяют вид временного отклика.","pt":"A transformada inversa de uma função racional obtém-se por decomposição em frações parciais, reconhecendo cada termo na tabela. Os polos determinam a forma da resposta temporal."},{"en":"Simple real pole","de":"Einfacher reeller Pol","fr":"Pôle réel simple","es":"Polo real simple","it":"Polo reale semplice","ru":"Простой вещественный полюс","pt":"Polo real simples"},{"en":"Multiple pole","de":"Mehrfacher Pol","fr":"Pôle multiple","es":"Polo múltiple","it":"Polo multiplo","ru":"Кратный полюс","pt":"Polo múltiplo"},{"en":"Complex-conjugate poles","de":"Konjugiert komplexe Pole","fr":"Pôles complexes conjugués","es":"Polos complejos conjugados","it":"Poli complessi coniugati","ru":"Комплексно-сопряжённые полюсы","pt":"Polos complexos conjugados"},{"en":"Find the original of","de":"Bestimme das Original von","fr":"Trouver l'original de","es":"Hallar el original de","it":"Trovare l'originale di","ru":"Найти оригинал для","pt":"Encontrar o original de"},{"en":"Partial-fraction expansion","de":"Partialbruchzerlegung","fr":"Décomposition en éléments simples","es":"Descomposición en fracciones simples","it":"Scomposizione in fratti semplici","ru":"Разложение на простейшие дроби","pt":"Decomposição em frações parciais"},{"en":"Each term from the table","de":"Jeder Term aus der Tabelle","fr":"Chaque terme depuis la table","es":"Cada término de la tabla","it":"Ogni termine dalla tabella","ru":"Каждый член по таблице","pt":"Cada termo da tabela"},{"en":"Fourier transform and properties","de":"Fourier-Transformation und Eigenschaften","fr":"Transformée de Fourier et propriétés","es":"Transformada de Fourier y propiedades","it":"Trasformata di Fourier e proprietà","ru":"Преобразование Фурье и свойства","pt":"Transformada de Fourier e propriedades"},{"en":"The Fourier transform describes the signal in the frequency domain. It exists if the signal is absolutely integrable, and is obtained from the Laplace transform by the substitution","de":"Die Fourier-Transformation beschreibt das Signal im Frequenzbereich. Sie existiert, wenn das Signal absolut integrierbar ist, und ergibt sich aus der Laplace-Transformation durch die Substitution","fr":"La transformée de Fourier décrit le signal dans le domaine fréquentiel. Elle existe si le signal est absolument intégrable, et s'obtient de la transformée de Laplace par la substitution","es":"La transformada de Fourier describe la señal en el dominio de la frecuencia. Existe si la señal es absolutamente integrable, y se obtiene de la de Laplace mediante la sustitución","it":"La trasformata di Fourier descrive il segnale nel dominio della frequenza. Esiste se il segnale è assolutamente integrabile e si ottiene da quella di Laplace con la sostituzione","ru":"Преобразование Фурье описывает сигнал в частотной области. Оно существует, если сигнал абсолютно интегрируем, и получается из преобразования Лапласа подстановкой","pt":"A transformada de Fourier descreve o sinal no domínio da frequência. Existe se o sinal for absolutamente integrável e obtém-se da de Laplace pela substituição"},{"en":"when the ROC contains the imaginary axis.","de":"wenn der ROC die imaginäre Achse enthält.","fr":"lorsque la ROC contient l'axe imaginaire.","es":"cuando la ROC contiene el eje imaginario.","it":"quando la ROC contiene l'asse immaginario.","ru":"когда ОС содержит мнимую ось.","pt":"quando a ROC contém o eixo imaginário."},{"en":"Forward transform","de":"Hintransformation","fr":"Transformée directe","es":"Transformada directa","it":"Trasformata diretta","ru":"Прямое преобразование","pt":"Transformada direta"},{"en":"Inverse transform","de":"Rücktransformation","fr":"Transformée inverse","es":"Transformada inversa","it":"Trasformata inversa","ru":"Обратное преобразование","pt":"Transformada inversa"},{"en":"Shift theorem","de":"Verschiebungssatz","fr":"Théorème du décalage","es":"Teorema del desplazamiento","it":"Teorema della traslazione","ru":"Теорема о сдвиге","pt":"Teorema do deslocamento"},{"en":"Parseval's theorem","de":"Satz von Parseval","fr":"Théorème de Parseval","es":"Teorema de Parseval","it":"Teorema di Parseval","ru":"Теорема Парсеваля","pt":"Teorema de Parseval"},{"en":"LTI systems: impulse response and transfer function","de":"LTI-Systeme: Impulsantwort und Übertragungsfunktion","fr":"Systèmes LTI : réponse impulsionnelle et fonction de transfert","es":"Sistemas LTI: respuesta al impulso y función de transferencia","it":"Sistemi LTI: risposta all'impulso e funzione di trasferimento","ru":"ЛСИ-системы: импульсная характеристика и передаточная функция","pt":"Sistemas LTI: resposta ao impulso e função de transferência"},{"en":"Linear time-invariant (LTI) systems are fully described by the impulse response","de":"Lineare zeitinvariante (LTI) Systeme werden vollständig durch die Impulsantwort beschrieben","fr":"Les systèmes linéaires invariants dans le temps (LTI) sont entièrement décrits par la réponse impulsionnelle","es":"Los sistemas lineales e invariantes en el tiempo (LTI) quedan totalmente descritos por la respuesta al impulso","it":"I sistemi lineari tempo-invarianti (LTI) sono completamente descritti dalla risposta all'impulso","ru":"Линейные стационарные (ЛСИ) системы полностью описываются импульсной характеристикой","pt":"Os sistemas lineares e invariantes no tempo (LTI) são totalmente descritos pela resposta ao impulso"},{"en":"The Laplace transform of the impulse response is the transfer function","de":"Die Laplace-Transformierte der Impulsantwort ist die Übertragungsfunktion","fr":"La transformée de Laplace de la réponse impulsionnelle est la fonction de transfert","es":"La transformada de Laplace de la respuesta al impulso es la función de transferencia","it":"La trasformata di Laplace della risposta all'impulso è la funzione di trasferimento","ru":"Преобразование Лапласа импульсной характеристики — это передаточная функция","pt":"A transformada de Laplace da resposta ao impulso é a função de transferência"},{"en":"and its value on the imaginary axis is the frequency response.","de":"und ihr Wert auf der imaginären Achse ist der Frequenzgang.","fr":"et sa valeur sur l'axe imaginaire est la réponse en fréquence.","es":"y su valor en el eje imaginario es la respuesta en frecuencia.","it":"e il suo valore sull'asse immaginario è la risposta in frequenza.","ru":"а её значение на мнимой оси — частотная характеристика.","pt":"e o seu valor no eixo imaginário é a resposta em frequência."},{"en":"Input-output relation","de":"Eingangs-Ausgangs-Beziehung","fr":"Relation entrée-sortie","es":"Relación entrada-salida","it":"Relazione ingresso-uscita","ru":"Соотношение вход-выход","pt":"Relação entrada-saída"},{"en":"Transfer function","de":"Übertragungsfunktion","fr":"Fonction de transfert","es":"Función de transferencia","it":"Funzione di trasferimento","ru":"Передаточная функция","pt":"Função de transferência"},{"en":"Frequency response","de":"Frequenzgang","fr":"Réponse en fréquence","es":"Respuesta en frecuencia","it":"Risposta in frequenza","ru":"Частотная характеристика","pt":"Resposta em frequência"},{"en":"The system is described by","de":"Das System wird beschrieben durch","fr":"Le système est décrit par","es":"El sistema se describe por","it":"Il sistema è descritto da","ru":"Система описана уравнением","pt":"O sistema é descrito por"},{"en":"and","de":"und","fr":"et","es":"y","it":"e","ru":"и","pt":"e"},{"en":"Transform (zero initial conditions)","de":"Transformation (verschwindende Anfangsbedingungen)","fr":"Transformée (conditions initiales nulles)","es":"Transformada (condiciones iniciales nulas)","it":"Trasformata (condizioni iniziali nulle)","ru":"Преобразование (нулевые начальные условия)","pt":"Transformada (condições iniciais nulas)"},{"en":"Classification and interconnection of systems","de":"Klassifikation und Verschaltung von Systemen","fr":"Classification et interconnexion des systèmes","es":"Clasificación e interconexión de sistemas","it":"Classificazione e interconnessione dei sistemi","ru":"Классификация и соединение систем","pt":"Classificação e interligação de sistemas"},{"en":"Systems are classified as linear or nonlinear, time-invariant or time-varying, with or without memory, causal and stable. Complex systems are built by series, parallel and feedback interconnection.","de":"Systeme werden als linear oder nichtlinear, zeitinvariant oder zeitvariant, mit oder ohne Gedächtnis, kausal und stabil klassifiziert. Komplexe Systeme entstehen durch Reihen-, Parallel- und Rückkopplungsschaltung.","fr":"On classe les systèmes en linéaires ou non, invariants ou variants dans le temps, avec ou sans mémoire, causaux et stables. Les systèmes complexes se construisent par interconnexion série, parallèle et à rétroaction.","es":"Los sistemas se clasifican en lineales o no lineales, invariantes o variantes en el tiempo, con o sin memoria, causales y estables. Los sistemas complejos se construyen por interconexión en serie, paralelo y realimentación.","it":"I sistemi si classificano in lineari o non lineari, tempo-invarianti o tempo-varianti, con o senza memoria, causali e stabili. I sistemi complessi si costruiscono con collegamenti in serie, parallelo e retroazione.","ru":"Системы классифицируют как линейные или нелинейные, стационарные или нестационарные, с памятью или без, причинные и устойчивые. Сложные системы строят последовательным, параллельным соединением и обратной связью.","pt":"Os sistemas classificam-se em lineares ou não lineares, invariantes ou variantes no tempo, com ou sem memória, causais e estáveis. Sistemas complexos constroem-se por ligação em série, paralelo e realimentação."},{"en":"Series connection","de":"Reihenschaltung","fr":"Connexion série","es":"Conexión en serie","it":"Collegamento in serie","ru":"Последовательное соединение","pt":"Ligação em série"},{"en":"Parallel connection","de":"Parallelschaltung","fr":"Connexion parallèle","es":"Conexión en paralelo","it":"Collegamento in parallelo","ru":"Параллельное соединение","pt":"Ligação em paralelo"},{"en":"Feedback","de":"Rückkopplung","fr":"Rétroaction","es":"Realimentación","it":"Retroazione","ru":"Обратная связь","pt":"Realimentação"},{"en":"Causality condition","de":"Kausalitätsbedingung","fr":"Condition de causalité","es":"Condición de causalidad","it":"Condizione di causalità","ru":"Условие причинности","pt":"Condição de causalidade"},{"en":"Forward branch","de":"Vorwärtszweig","fr":"Branche directe","es":"Rama directa","it":"Ramo diretto","ru":"Прямая ветвь","pt":"Ramo direto"},{"en":"feedback","de":"Rückführung","fr":"retour","es":"realimentación","it":"retroazione","ru":"обратная","pt":"realimentação"},{"en":"Find the equivalent transfer function.","de":"Bestimme die äquivalente Übertragungsfunktion.","fr":"Trouver la fonction de transfert équivalente.","es":"Hallar la función de transferencia equivalente.","it":"Trovare la funzione di trasferimento equivalente.","ru":"Найти эквивалентную передаточную функцию.","pt":"Encontrar a função de transferência equivalente."},{"en":"Time-domain analysis and stability","de":"Zeitbereichsanalyse und Stabilität","fr":"Analyse temporelle et stabilité","es":"Análisis en el dominio del tiempo y estabilidad","it":"Analisi nel dominio del tempo e stabilità","ru":"Анализ во временной области и устойчивость","pt":"Análise no domínio do tempo e estabilidade"},{"en":"In the time domain the response is found by convolution. A system is BIBO stable if every bounded input yields a bounded output; this is equivalent to absolute integrability of the impulse response, i.e. poles in the left half-plane.","de":"Im Zeitbereich findet man die Antwort durch Faltung. Ein System ist BIBO-stabil, wenn jeder beschränkte Eingang einen beschränkten Ausgang liefert; das entspricht der absoluten Integrierbarkeit der Impulsantwort bzw. Polen in der linken Halbebene.","fr":"Dans le domaine temporel, la réponse s'obtient par convolution. Un système est BIBO-stable si toute entrée bornée donne une sortie bornée ; cela équivaut à l'intégrabilité absolue de la réponse impulsionnelle, c.-à-d. des pôles dans le demi-plan gauche.","es":"En el dominio del tiempo la respuesta se halla por convolución. Un sistema es BIBO estable si toda entrada acotada produce una salida acotada; equivale a la integrabilidad absoluta de la respuesta al impulso, es decir, polos en el semiplano izquierdo.","it":"Nel dominio del tempo la risposta si trova per convoluzione. Un sistema è BIBO-stabile se ogni ingresso limitato dà un'uscita limitata; equivale all'integrabilità assoluta della risposta all'impulso, cioè poli nel semipiano sinistro.","ru":"Во временной области отклик находят свёрткой. Система BIBO-устойчива, если любой ограниченный вход даёт ограниченный выход; это эквивалентно абсолютной интегрируемости импульсной характеристики, т. е. полюсам в левой полуплоскости.","pt":"No domínio do tempo a resposta obtém-se por convolução. Um sistema é BIBO estável se toda entrada limitada produz saída limitada; equivale à integrabilidade absoluta da resposta ao impulso, isto é, polos no semiplano esquerdo."},{"en":"BIBO condition (impulse response)","de":"BIBO-Bedingung (Impulsantwort)","fr":"Condition BIBO (réponse impulsionnelle)","es":"Condición BIBO (respuesta al impulso)","it":"Condizione BIBO (risposta all'impulso)","ru":"Условие BIBO (импульсная характеристика)","pt":"Condição BIBO (resposta ao impulso)"},{"en":"Condition via poles","de":"Bedingung über die Pole","fr":"Condition par les pôles","es":"Condición mediante polos","it":"Condizione tramite i poli","ru":"Условие через полюсы","pt":"Condição pelos polos"},{"en":"Marginal stability","de":"Grenzstabilität","fr":"Stabilité marginale","es":"Estabilidad marginal","it":"Stabilità marginale","ru":"Граничная устойчивость","pt":"Estabilidade marginal"},{"en":"Is the system","de":"Ist das System","fr":"Le système est-il","es":"¿Es el sistema","it":"Il sistema è","ru":"Является ли система","pt":"O sistema é"},{"en":"stable?","de":"stabil?","fr":"stable ?","es":"estable?","it":"stabile?","ru":"устойчивой?","pt":"estável?"},{"en":"Poles","de":"Pole","fr":"Pôles","es":"Polos","it":"Poli","ru":"Полюсы","pt":"Polos"},{"en":"Both poles are in the left half-plane, so the system is stable.","de":"Beide Pole liegen in der linken Halbebene, also ist das System stabil.","fr":"Les deux pôles sont dans le demi-plan gauche, donc le système est stable.","es":"Ambos polos están en el semiplano izquierdo, por lo que el sistema es estable.","it":"Entrambi i poli sono nel semipiano sinistro, quindi il sistema è stabile.","ru":"Оба полюса в левой полуплоскости, поэтому система устойчива.","pt":"Ambos os polos estão no semiplano esquerdo, logo o sistema é estável."},{"en":"Analysis via the unilateral Laplace transform","de":"Analyse mittels einseitiger Laplace-Transformation","fr":"Analyse par la transformée de Laplace unilatérale","es":"Análisis mediante la transformada de Laplace unilateral","it":"Analisi tramite la trasformata di Laplace unilatera","ru":"Анализ с помощью одностороннего преобразования Лапласа","pt":"Análise pela transformada de Laplace unilateral"},{"en":"The unilateral Laplace transform solves the system's differential equations with initial conditions: the equation becomes algebraic and is solved for","de":"Die einseitige Laplace-Transformation löst die Differentialgleichungen des Systems mit Anfangsbedingungen: die Gleichung wird algebraisch und wird gelöst nach","fr":"La transformée de Laplace unilatérale résout les équations différentielles du système avec conditions initiales : l'équation devient algébrique et se résout pour","es":"La transformada de Laplace unilateral resuelve las ecuaciones diferenciales del sistema con condiciones iniciales: la ecuación se vuelve algebraica y se resuelve para","it":"La trasformata di Laplace unilatera risolve le equazioni differenziali del sistema con condizioni iniziali: l'equazione diventa algebrica e si risolve per","ru":"Одностороннее преобразование Лапласа решает дифференциальные уравнения системы с начальными условиями: уравнение становится алгебраическим и решается относительно","pt":"A transformada de Laplace unilateral resolve as equações diferenciais do sistema com condições iniciais: a equação torna-se algébrica e resolve-se para"},{"en":"then the response is obtained by the inverse transform.","de":"dann erhält man die Antwort durch Rücktransformation.","fr":"puis la réponse s'obtient par la transformée inverse.","es":"luego la respuesta se obtiene por la transformada inversa.","it":"poi la risposta si ottiene con la trasformata inversa.","ru":"затем отклик получают обратным преобразованием.","pt":"depois a resposta obtém-se pela transformada inversa."},{"en":"Derivative with initial condition","de":"Ableitung mit Anfangsbedingung","fr":"Dérivée avec condition initiale","es":"Derivada con condición inicial","it":"Derivata con condizione iniziale","ru":"Производная с начальным условием","pt":"Derivada com condição inicial"},{"en":"Second derivative","de":"Zweite Ableitung","fr":"Dérivée seconde","es":"Segunda derivada","it":"Derivata seconda","ru":"Вторая производная","pt":"Segunda derivada"},{"en":"System response","de":"Systemantwort","fr":"Réponse du système","es":"Respuesta del sistema","it":"Risposta del sistema","ru":"Отклик системы","pt":"Resposta do sistema"},{"en":"Solve","de":"Löse","fr":"Résoudre","es":"Resolver","it":"Risolvere","ru":"Решить","pt":"Resolver"},{"en":"Analysis via the Fourier transform","de":"Analyse mittels Fourier-Transformation","fr":"Analyse par la transformée de Fourier","es":"Análisis mediante la transformada de Fourier","it":"Analisi tramite la trasformata di Fourier","ru":"Анализ с помощью преобразования Фурье","pt":"Análise pela transformada de Fourier"},{"en":"Fourier analysis gives the system's frequency response. The output spectrum is the product of the input spectrum and the frequency response, so the magnitude and phase characteristics describe how the system passes individual frequencies.","de":"Die Fourier-Analyse liefert den Frequenzgang des Systems. Das Ausgangsspektrum ist das Produkt aus Eingangsspektrum und Frequenzgang, sodass Amplituden- und Phasengang beschreiben, wie das System einzelne Frequenzen durchlässt.","fr":"L'analyse de Fourier donne la réponse en fréquence du système. Le spectre de sortie est le produit du spectre d'entrée et de la réponse en fréquence ; les caractéristiques d'amplitude et de phase décrivent comment le système laisse passer chaque fréquence.","es":"El análisis de Fourier da la respuesta en frecuencia del sistema. El espectro de salida es el producto del espectro de entrada y la respuesta en frecuencia, de modo que las características de amplitud y fase describen cómo el sistema deja pasar cada frecuencia.","it":"L'analisi di Fourier dà la risposta in frequenza del sistema. Lo spettro d'uscita è il prodotto dello spettro d'ingresso e della risposta in frequenza, quindi le caratteristiche di ampiezza e fase descrivono come il sistema lascia passare le singole frequenze.","ru":"Анализ Фурье даёт частотную характеристику системы. Спектр выхода — произведение спектра входа и частотной характеристики, поэтому амплитудная и фазовая характеристики описывают, как система пропускает отдельные частоты.","pt":"A análise de Fourier dá a resposta em frequência do sistema. O espetro de saída é o produto do espetro de entrada e da resposta em frequência, pelo que as características de amplitude e fase descrevem como o sistema deixa passar cada frequência."},{"en":"Output spectrum","de":"Ausgangsspektrum","fr":"Spectre de sortie","es":"Espectro de salida","it":"Spettro d'uscita","ru":"Спектр выхода","pt":"Espetro de saída"},{"en":"Magnitude characteristic","de":"Amplitudengang","fr":"Caractéristique d'amplitude","es":"Característica de amplitud","it":"Caratteristica di ampiezza","ru":"Амплитудная характеристика","pt":"Característica de amplitude"},{"en":"Phase characteristic","de":"Phasengang","fr":"Caractéristique de phase","es":"Característica de fase","it":"Caratteristica di fase","ru":"Фазовая характеристика","pt":"Característica de fase"},{"en":"For","de":"Für","fr":"Pour","es":"Para","it":"Per","ru":"Для","pt":"Para"},{"en":"find the magnitude at","de":"bestimme die Amplitude bei","fr":"trouver l'amplitude à","es":"hallar la amplitud en","it":"trovare l'ampiezza a","ru":"найти амплитуду при","pt":"encontrar a amplitude em"},{"en":"This is the passband edge (a drop of","de":"Das ist die Durchlassbandgrenze (Abfall von","fr":"C'est la limite de la bande passante (chute de","es":"Es el borde de la banda de paso (caída de","it":"È il limite della banda passante (caduta di","ru":"Это граница полосы пропускания (спад на","pt":"É o limite da banda de passagem (queda de"},{"en":"Filtering: classification of filters","de":"Filterung: Klassifikation der Filter","fr":"Filtrage : classification des filtres","es":"Filtrado: clasificación de filtros","it":"Filtraggio: classificazione dei filtri","ru":"Фильтрация: классификация фильтров","pt":"Filtragem: classificação dos filtros"},{"en":"A filter is a system that selectively passes frequencies. By passband we distinguish low-pass (LP), high-pass (HP), band-pass (BP) and band-stop (BS). Ideal filters have a rectangular magnitude characteristic but are not realizable.","de":"Ein Filter ist ein System, das Frequenzen selektiv durchlässt. Nach dem Durchlassband unterscheidet man Tiefpass (TP), Hochpass (HP), Bandpass (BP) und Bandsperre (BS). Ideale Filter haben einen rechteckigen Amplitudengang, sind aber nicht realisierbar.","fr":"Un filtre est un système qui laisse passer sélectivement des fréquences. Selon la bande passante on distingue passe-bas (PB), passe-haut (PH), passe-bande (PBd) et coupe-bande (CB). Les filtres idéaux ont une caractéristique d'amplitude rectangulaire mais ne sont pas réalisables.","es":"Un filtro es un sistema que deja pasar selectivamente frecuencias. Por banda de paso se distinguen paso-bajo (PB), paso-alto (PA), paso-banda (PBa) y rechazo-banda (RB). Los filtros ideales tienen característica de amplitud rectangular pero no son realizables.","it":"Un filtro è un sistema che lascia passare selettivamente le frequenze. Per banda passante si distinguono passa-basso (PB), passa-alto (PA), passa-banda (PBd) e elimina-banda (EB). I filtri ideali hanno caratteristica di ampiezza rettangolare ma non sono realizzabili.","ru":"Фильтр — система, избирательно пропускающая частоты. По полосе пропускания различают фильтры нижних частот (ФНЧ), верхних частот (ФВЧ), полосовой (ПФ) и режекторный (РФ). Идеальные фильтры имеют прямоугольную амплитудную характеристику, но нереализуемы.","pt":"Um filtro é um sistema que deixa passar seletivamente frequências. Pela banda de passagem distinguem-se passa-baixo (PB), passa-alto (PA), passa-banda (PBd) e rejeita-banda (RB). Os filtros ideais têm característica de amplitude retangular mas não são realizáveis."},{"en":"Ideal low-pass filter","de":"Idealer Tiefpass","fr":"Filtre passe-bas idéal","es":"Filtro paso-bajo ideal","it":"Filtro passa-basso ideale","ru":"Идеальный фильтр нижних частот","pt":"Filtro passa-baixo ideal"},{"en":"Cutoff frequency (3 dB)","de":"Grenzfrequenz (3 dB)","fr":"Fréquence de coupure (3 dB)","es":"Frecuencia de corte (3 dB)","it":"Frequenza di taglio (3 dB)","ru":"Частота среза (3 дБ)","pt":"Frequência de corte (3 dB)"},{"en":"Gain in decibels","de":"Verstärkung in Dezibel","fr":"Gain en décibels","es":"Ganancia en decibelios","it":"Guadagno in decibel","ru":"Усиление в децибелах","pt":"Ganho em decibéis"},{"en":"Determine the cutoff frequency of an RC low-pass filter","de":"Bestimme die Grenzfrequenz eines RC-Tiefpasses","fr":"Déterminer la fréquence de coupure d'un passe-bas RC","es":"Determinar la frecuencia de corte de un filtro paso-bajo RC","it":"Determinare la frequenza di taglio di un passa-basso RC","ru":"Определить частоту среза RC-фильтра нижних частот","pt":"Determinar a frequência de corte de um passa-baixo RC"},{"en":"The cutoff frequency is where the denominator has magnitude","de":"Die Grenzfrequenz liegt dort, wo der Nenner den Betrag hat","fr":"La fréquence de coupure est là où le dénominateur a pour module","es":"La frecuencia de corte está donde el denominador tiene módulo","it":"La frequenza di taglio è dove il denominatore ha modulo","ru":"Частота среза там, где знаменатель имеет модуль","pt":"A frequência de corte é onde o denominador tem módulo"},{"en":"Filter synthesis: Butterworth and Chebyshev","de":"Filtersynthese: Butterworth und Tschebyscheff","fr":"Synthèse de filtres : Butterworth et Tchebychev","es":"Síntesis de filtros: Butterworth y Chebyshev","it":"Sintesi di filtri: Butterworth e Chebyshev","ru":"Синтез фильтров: Баттерворт и Чебышёв","pt":"Síntese de filtros: Butterworth e Chebyshev"},{"en":"Synthesis starts from a given magnitude specification and chooses an approximation. The Butterworth approximation is maximally flat in the passband, while the Chebyshev one allows ripple for a steeper transition.","de":"Die Synthese geht von einer Amplitudenvorgabe aus und wählt eine Approximation. Die Butterworth-Approximation ist im Durchlassband maximal flach, die Tschebyscheff-Approximation erlaubt Welligkeit für einen steileren Übergang.","fr":"La synthèse part d'une spécification d'amplitude et choisit une approximation. L'approximation de Butterworth est maximalement plate dans la bande passante, celle de Tchebychev autorise une ondulation pour une transition plus raide.","es":"La síntesis parte de una especificación de amplitud y elige una aproximación. La aproximación de Butterworth es máximamente plana en la banda de paso, mientras que la de Chebyshev permite rizado para una transición más abrupta.","it":"La sintesi parte da una specifica di ampiezza e sceglie un'approssimazione. L'approssimazione di Butterworth è massimamente piatta in banda passante, quella di Chebyshev consente ondulazione per una transizione più ripida.","ru":"Синтез исходит из заданной амплитудной спецификации и выбирает аппроксимацию. Аппроксимация Баттерворта максимально плоская в полосе пропускания, а Чебышёва допускает пульсации ради более крутого перехода.","pt":"A síntese parte de uma especificação de amplitude e escolhe uma aproximação. A aproximação de Butterworth é maximamente plana na banda de passagem, enquanto a de Chebyshev permite ondulação para uma transição mais abrupta."},{"en":"Butterworth response","de":"Butterworth-Charakteristik","fr":"Réponse de Butterworth","es":"Respuesta de Butterworth","it":"Risposta di Butterworth","ru":"Характеристика Баттерворта","pt":"Resposta de Butterworth"},{"en":"Chebyshev response","de":"Tschebyscheff-Charakteristik","fr":"Réponse de Tchebychev","es":"Respuesta de Chebyshev","it":"Risposta di Chebyshev","ru":"Характеристика Чебышёва","pt":"Resposta de Chebyshev"},{"en":"Butterworth poles on a circle","de":"Butterworth-Pole auf einem Kreis","fr":"Pôles de Butterworth sur un cercle","es":"Polos de Butterworth en una circunferencia","it":"Poli di Butterworth su una circonferenza","ru":"Полюсы Баттерворта на окружности","pt":"Polos de Butterworth numa circunferência"},{"en":"What attenuation does a Butterworth filter have","de":"Welche Dämpfung hat ein Butterworth-Filter","fr":"Quelle atténuation a un filtre de Butterworth","es":"Qué atenuación tiene un filtro Butterworth","it":"Quale attenuazione ha un filtro Butterworth","ru":"Какое ослабление у фильтра Баттерворта","pt":"Que atenuação tem um filtro Butterworth"},{"en":"at","de":"bei","fr":"à","es":"en","it":"a","ru":"при","pt":"em"},{"en":"Analog filters and their realization","de":"Analoge Filter und ihre Realisierung","fr":"Filtres analogiques et leur réalisation","es":"Filtros analógicos y su realización","it":"Filtri analogici e loro realizzazione","ru":"Аналоговые фильтры и их реализация","pt":"Filtros analógicos e a sua realização"},{"en":"The designed transfer function is realized by passive (RLC) or active circuits. Active filters with an operational amplifier (e.g. Sallen-Key) do not load the signal and cascade easily. The second-order section is the building block of higher orders.","de":"Die entworfene Übertragungsfunktion wird durch passive (RLC) oder aktive Schaltungen realisiert. Aktive Filter mit Operationsverstärker (z. B. Sallen-Key) belasten das Signal nicht und lassen sich leicht kaskadieren. Die Sektion zweiter Ordnung ist der Baustein höherer Ordnungen.","fr":"La fonction de transfert conçue se réalise par des circuits passifs (RLC) ou actifs. Les filtres actifs à amplificateur opérationnel (p. ex. Sallen-Key) ne chargent pas le signal et se mettent facilement en cascade. La section du second ordre est le bloc de base des ordres supérieurs.","es":"La función de transferencia diseñada se realiza con circuitos pasivos (RLC) o activos. Los filtros activos con amplificador operacional (p. ej. Sallen-Key) no cargan la señal y se conectan fácilmente en cascada. La sección de segundo orden es el bloque de los órdenes superiores.","it":"La funzione di trasferimento progettata si realizza con circuiti passivi (RLC) o attivi. I filtri attivi con amplificatore operazionale (es. Sallen-Key) non caricano il segnale e si mettono facilmente in cascata. La sezione del secondo ordine è il blocco degli ordini superiori.","ru":"Спроектированную передаточную функцию реализуют пассивными (RLC) или активными цепями. Активные фильтры с операционным усилителем (напр. Саллена–Ки) не нагружают сигнал и легко каскадируются. Звено второго порядка — строительный блок высших порядков.","pt":"A função de transferência projetada realiza-se com circuitos passivos (RLC) ou ativos. Os filtros ativos com amplificador operacional (p. ex. Sallen-Key) não carregam o sinal e ligam-se facilmente em cascata. A secção de segunda ordem é o bloco das ordens superiores."},{"en":"Second-order section (LP)","de":"Sektion zweiter Ordnung (TP)","fr":"Section du second ordre (PB)","es":"Sección de segundo orden (PB)","it":"Sezione del secondo ordine (PB)","ru":"Звено второго порядка (ФНЧ)","pt":"Secção de segunda ordem (PB)"},{"en":"Natural frequency and quality factor","de":"Eigenfrequenz und Güte","fr":"Fréquence propre et facteur de qualité","es":"Frecuencia natural y factor de calidad","it":"Frequenza propria e fattore di qualità","ru":"Собственная частота и добротность","pt":"Frequência natural e fator de qualidade"},{"en":"Cascading sections","de":"Kaskadierung von Sektionen","fr":"Mise en cascade des sections","es":"Conexión en cascada de secciones","it":"Cascata di sezioni","ru":"Каскадирование звеньев","pt":"Cascata de secções"},{"en":"For a second-order section with","de":"Für eine Sektion zweiter Ordnung mit","fr":"Pour une section du second ordre avec","es":"Para una sección de segundo orden con","it":"Per una sezione del secondo ordine con","ru":"Для звена второго порядка с","pt":"Para uma secção de segunda ordem com"},{"en":"determine the type of damping.","de":"bestimme die Art der Dämpfung.","fr":"déterminer le type d'amortissement.","es":"determinar el tipo de amortiguamiento.","it":"determinare il tipo di smorzamento.","ru":"определить тип затухания.","pt":"determinar o tipo de amortecimento."},{"en":"corresponds to the Butterworth (maximally flat) response.","de":"entspricht der Butterworth- (maximal flachen) Antwort.","fr":"correspond à la réponse de Butterworth (maximalement plate).","es":"corresponde a la respuesta de Butterworth (máximamente plana).","it":"corrisponde alla risposta di Butterworth (massimamente piatta).","ru":"соответствует характеристике Баттерворта (максимально плоской).","pt":"corresponde à resposta de Butterworth (maximamente plana)."},{"en":"The poles are complex-conjugate with an angle of","de":"Die Pole sind konjugiert komplex mit einem Winkel von","fr":"Les pôles sont complexes conjugués avec un angle de","es":"Los polos son complejos conjugados con un ángulo de","it":"I poli sono complessi coniugati con un angolo di","ru":"Полюсы комплексно-сопряжённые с углом","pt":"Os polos são complexos conjugados com um ângulo de"},{"en":"with respect to the real axis.","de":"bezogen auf die reelle Achse.","fr":"par rapport à l'axe réel.","es":"respecto al eje real.","it":"rispetto all'asse reale.","ru":"относительно вещественной оси.","pt":"em relação ao eixo real."},{"en":"There is no ripple in the passband; the transition is smooth.","de":"Es gibt keine Welligkeit im Durchlassband; der Übergang ist glatt.","fr":"Il n'y a pas d'ondulation dans la bande passante ; la transition est douce.","es":"No hay rizado en la banda de paso; la transición es suave.","it":"Non c'è ondulazione in banda passante; la transizione è dolce.","ru":"В полосе пропускания нет пульсаций; переход гладкий.","pt":"Não há ondulação na banda de passagem; a transição é suave."},{"en":"Laplace transform","de":"Laplace-Transformation","fr":"Transformée de Laplace","es":"Transformada de Laplace","it":"Trasformata di Laplace","ru":"Преобразование Лапласа","pt":"Transformada de Laplace"},{"en":"Table of Laplace pairs","de":"Tabelle der Laplace-Paare","fr":"Table des paires de Laplace","es":"Tabla de pares de Laplace","it":"Tabella delle coppie di Laplace","ru":"Таблица пар Лапласа","pt":"Tabela de pares de Laplace"},{"en":"Step","de":"Sprung","fr":"Échelon","es":"Escalón","it":"Gradino","ru":"Скачок","pt":"Degrau"},{"en":"Exponential","de":"Exponential","fr":"Exponentielle","es":"Exponencial","it":"Esponenziale","ru":"Экспонента","pt":"Exponencial"},{"en":"Sine","de":"Sinus","fr":"Sinus","es":"Seno","it":"Seno","ru":"Синус","pt":"Seno"},{"en":"Cosine","de":"Kosinus","fr":"Cosinus","es":"Coseno","it":"Coseno","ru":"Косинус","pt":"Cosseno"},{"en":"Damped sinusoid","de":"Gedämpfte Sinusschwingung","fr":"Sinusoïde amortie","es":"Sinusoide amortiguada","it":"Sinusoide smorzata","ru":"Затухающая синусоида","pt":"Sinusoide amortecida"},{"en":"Fourier transform","de":"Fourier-Transformation","fr":"Transformée de Fourier","es":"Transformada de Fourier","it":"Trasformata di Fourier","ru":"Преобразование Фурье","pt":"Transformada de Fourier"},{"en":"LTI systems","de":"LTI-Systeme","fr":"Systèmes LTI","es":"Sistemas LTI","it":"Sistemi LTI","ru":"ЛСИ-системы","pt":"Sistemas LTI"},{"en":"Stability","de":"Stabilität","fr":"Stabilité","es":"Estabilidad","it":"Stabilità","ru":"Устойчивость","pt":"Estabilidade"},{"en":"Filters","de":"Filter","fr":"Filtres","es":"Filtros","it":"Filtri","ru":"Фильтры","pt":"Filtros"}];
